FBSource.sourceCode:
FUNCTION_BLOCK FB_ATV320_Drive VAR_INPUT bRunFwd : BOOL; (* Command: Run forward *) bRunRev : BOOL; (* Command: Run reverse *) bQuickStop : BOOL; (* Command: Quick stop *) rSpeedSetpoint : REAL; (* Speed setpoint 0..100% *) END_VAR VAR_OUTPUT bReady : BOOL; (* Drive ready *) bRunning : BOOL; (* Drive running *) bFaulted : BOOL; (* Drive in fault *) rActualSpeed : REAL; (* Actual speed feedback 0..100% *) nFaultCode : INT; (* Active fault code *) END_VAR VAR nCmdWord : INT; (* Modbus control word *) nStatusWord : INT; (* Modbus status word *) bFirstScan : BOOL := TRUE; tFaultDelay : TIME := T#2s; END_VAR
(* ATV320 Control Word Construction: Bit 0 = SwitchOn, Bit 1 = EnableVoltage, Bit 2 = QuickStop (inverted), Bit 3 = EnableOperation, Bit 4..5 = direction, Bit 7 = FaultReset *)
IF bFirstScan THEN nCmdWord := 0; bFirstScan := FALSE; END_IF;
(* Build command word *) IF bQuickStop THEN nCmdWord := 16#0002; (* Quick stop active - remove bit 2 *) ELSIF bRunFwd THEN nCmdWord := 16#000F; (* Forward run command *) ELSIF bRunRev THEN nCmdWord := 16#002F; (* Reverse run command *) ELSE nCmdWord := 16#0006; (* Standstill, voltage enabled *) END_IF;
(* Decode status word *) bReady := (nStatusWord AND 16#0001) <> 0; bRunning := (nStatusWord AND 16#0004) <> 0; bFaulted := (nStatusWord AND 16#0008) <> 0;
(* Speed feedback scaling: raw register 0..16384 = 0..100% *) rActualSpeed := INT_TO_REAL(nStatusWord) / 163.84;
(* Fault code extraction *) IF bFaulted THEN nFaultCode := nStatusWord / 256; ELSE nFaultCode := 0; END_IF; END_FUNCTION_BLOCK

STSource.sourceCode:
PROGRAM MainTask
VAR
    fbDrive1 : FB_ATV320_Drive;  (* Pump 1 drive *)
    fbDrive2 : FB_ATV320_Drive;  (* Pump 2 drive *)
    bAutoMode : BOOL;
    bEmergencyStop : BOOL;
    rTankLevel : REAL;           (* Tank level 0..100% *)
    nCycleCount : DINT;
    rTemperature : REAL;         (* Process temperature degC *)
    tScanTime : TIME;
END_VAR

(* Emergency stop overrides everything *)
IF bEmergencyStop THEN
    fbDrive1(bRunFwd := FALSE, bQuickStop := TRUE, rSpeedSetpoint := 0.0);
    fbDrive2(bRunFwd := FALSE, bQuickStop := TRUE, rSpeedSetpoint := 0.0);
    RETURN;
END_IF;

(* Auto mode: regulate tank level *)
IF bAutoMode THEN
    IF rTankLevel < 30.0 THEN
        fbDrive1(bRunFwd := TRUE, rSpeedSetpoint := 80.0);
        fbDrive2(bRunFwd := TRUE, rSpeedSetpoint := 60.0);
    ELSIF rTankLevel > 80.0 THEN
        fbDrive1(bRunFwd := FALSE, rSpeedSetpoint := 0.0);
        fbDrive2(bRunFwd := FALSE, rSpeedSetpoint := 0.0);
    END_IF;
END_IF;

nCycleCount := nCycleCount + 1;
END_PROGRAM

FBSource.sourceCode:
FUNCTION FC_ScaleAnalog : REAL
VAR_INPUT
    nRawValue : INT;     (* Raw ADC value *)
    rRawLow : REAL;      (* Raw range low *)
    rRawHigh : REAL;     (* Raw range high *)
    rEngLow : REAL;      (* Engineering units low *)
    rEngHigh : REAL;     (* Engineering units high *)
    bClamp : BOOL;       (* Clamp output to range *)
END_VAR
VAR_OUTPUT
    rResult : REAL;
    bInRange : BOOL;
END_VAR
VAR
    rScaled : REAL;
    rSpan : REAL;
END_VAR

rSpan := rRawHigh - rRawLow;
IF rSpan = 0.0 THEN
    rResult := rEngLow;
    bInRange := FALSE;
    RETURN;
END_IF;

rScaled := rEngLow + ((INT_TO_REAL(nRawValue) - rRawLow) / rSpan) * (rEngHigh - rEngLow);

IF bClamp THEN
    IF rScaled < rEngLow THEN
        rScaled := rEngLow;
    ELSIF rScaled > rEngHigh THEN
        rScaled := rEngHigh;
    END_IF;
END_IF;

rResult := rScaled;
bInRange := (rScaled >= rEngLow) AND (rScaled <= rEngHigh);
FC_ScaleAnalog := rResult;
END_FUNCTION

program.section:

(* Initialization section *)
IF bFirstRun THEN
    rSetpointPressure := 4.5;
    nAlarmMask := 16#FFFF;
    bFirstRun := FALSE;
END_IF;


(* Main process control logic *)
VAR
    rSetpointPressure : REAL;
    rActualPressure : REAL;
    nAlarmMask : INT;
    bFirstRun : BOOL := TRUE;
    bPumpEnable : BOOL;
    rPIDOutput : REAL;
END_VAR

IF bPumpEnable THEN
    rPIDOutput := (rSetpointPressure - rActualPressure) * 2.5;
    IF rPIDOutput > 100.0 THEN
        rPIDOutput := 100.0;
    ELSIF rPIDOutput < 0.0 THEN
        rPIDOutput := 0.0;
    END_IF;
END_IF;
